    85→            } else {
    86→                Either::Right(local)
    87→            }
    88→        });
    89→
    90→    debug!("{} total variables", body.local_decls.len());
    91→    debug!("{} variables need liveness", relevant_live_locals.len());
    92→    debug!("{} regions outlive free regions", free_regions.len());
